import json
from datetime import datetime

opps = locals()['var_functions.query_db:8']
contracts_partial = [
    {"Id": "800Wt00000DE8sgIAD", "CompanySignedDate": "2023-10-13"},
    {"Id": "800Wt00000DE9ryIAD", "CompanySignedDate": "2023-09-30"}
]

contracts_dict = {c['Id']: c for c in contracts_partial}

# Calculate sales cycles
sales_cycles = []
for opp in opps:
    contract_id = opp['ContractID__c']
    if contract_id in contracts_dict:
        created_str = opp['CreatedDate']
        signed_str = contracts_dict[contract_id]['CompanySignedDate']

        created = datetime.fromisoformat(created_str.replace('Z', '+00:00'))
        signed = datetime.fromisoformat(signed_str + 'T00:00:00+00:00')

        days = (signed - created).days

        sales_cycles.append({
            'OwnerId': opp['OwnerId'],
            'Days': days
        })

# Group by agent
from collections import defaultdict
agent_cycles = defaultdict(list)
for sc in sales_cycles:
    agent_cycles[sc['OwnerId']].append(sc['Days'])

# Calculate averages
agent_averages = {}
for agent, days in agent_cycles.items():
    avg = sum(days) / len(days)
    agent_averages[agent] = {
        'avg_days': avg,
        'count': len(days)
    }

print("Agent averages:")
for agent, data in sorted(agent_averages.items(), key=lambda x: x[1]['avg_days']):
    print(f"Agent {agent}: {data['avg_days']:.1f} days avg ({data['count']} opp)")

if agent_averages:
    quickest = min(agent_averages.items(), key=lambda x: x[1]['avg_days'])
    result = quickest[0]
else:
    result = None

print(f"\nQuickest agent: {result}")

print("__RESULT__:")
print(json.dumps(result))

